// Onglets système à exclure (gid=0 : objectifs revenue, gid=4832360 : process template)
const EXCLUDE_GIDS = [0, 4832360];

const spreadsheet = items[0].json;
const sheets = spreadsheet.sheets || [];
const rows = [];

sheets.forEach(sheet => {
  const props = sheet.properties || {};
  // Exclure les onglets système
  if (EXCLUDE_GIDS.includes(props.sheetId)) return;

  const topic = props.title || '';
  const grid  = sheet.data?.[0];
  if (!grid || !grid.rowData || grid.rowData.length < 2) return;

  // 1ère ligne = en-têtes
  const headers = (grid.rowData[0]?.values || []).map(v => v.formattedValue || '');
  if (!headers.some(Boolean)) return;

  // Lignes de données (à partir de la 2ème)
  for (let i = 1; i < grid.rowData.length; i++) {
    const vals = (grid.rowData[i]?.values || []).map(v => v.formattedValue || '');
    if (!vals.some(Boolean)) continue; // ignorer les lignes vides

    const row = { _topic: topic };
    headers.forEach((h, j) => { if (h) row[h] = vals[j] || ''; });
    rows.push(row);
  }
});

return [{ json: { success: true, count: rows.length, rows } }];
